import {
IMessageDataWrapper,
IMessageParser,
} from '@nitrots/nitro-renderer/src/core';

export interface UserStatsData {
// --- header / identity ---
userId: number; // 01
username: string; // 02
figure: string; // 03

// --- core stats ---
health: number; // 04
maxHealth: number; // 05
energy: number; // 06
maxEnergy: number; // 07
hunger: number; // 08
maxHunger: number; // 09
aggressionMs: number; // 10 (server sends milliseconds)

// --- progression ---
xp: number; // 11
maxXP: number; // 12
strength: number; // 13
level: number; // 14
points: number; // 15
stamina: number; // 16
hunger_level: number; // 17
gathering: number; // 18
defense: number; // 19

// --- combat / counters ---
punches_thrown: number; // 20
punches_landed: number; // 21
damage_inflicted: number; // 22
damage_received: number; // 23
shifts_worked: number; // 24
kills: number; // 25
deaths: number; // 26
arrests: number; // 27

// --- flags & meta ---
isAggressive: boolean; // 28
working: boolean; // 29
dead: boolean; // 30
gangName: string; // 31
}

export class UserStatsParser implements IMessageParser {
private _stats: UserStatsData = this._blank();

public flush(): boolean {
this._stats = this._blank();
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean {
// ----- MUST match server order exactly -----

// header
this._stats.userId = wrapper.readInt(); // 01
this._stats.username = wrapper.readString(); // 02
this._stats.figure = wrapper.readString(); // 03

// core stats
this._stats.health = wrapper.readInt(); // 04
this._stats.maxHealth = wrapper.readInt(); // 05
this._stats.energy = wrapper.readInt(); // 06
this._stats.maxEnergy = wrapper.readInt(); // 07
this._stats.hunger = wrapper.readInt(); // 08
this._stats.maxHunger = wrapper.readInt(); // 09
this._stats.aggressionMs = wrapper.readInt();// 10 (ms)

// progression
this._stats.xp = wrapper.readInt(); // 11
this._stats.maxXP = wrapper.readInt(); // 12
this._stats.strength = wrapper.readInt(); // 13
this._stats.level = wrapper.readInt(); // 14
this._stats.points = wrapper.readInt(); // 15
this._stats.stamina = wrapper.readInt(); // 16
this._stats.hunger_level = wrapper.readInt();// 17
this._stats.gathering = wrapper.readInt(); // 18
this._stats.defense = wrapper.readInt(); // 19

// counters
this._stats.punches_thrown = wrapper.readInt(); // 20
this._stats.punches_landed = wrapper.readInt(); // 21
this._stats.damage_inflicted = wrapper.readInt(); // 22
this._stats.damage_received = wrapper.readInt(); // 23
this._stats.shifts_worked = wrapper.readInt(); // 24
this._stats.kills = wrapper.readInt(); // 25
this._stats.deaths = wrapper.readInt(); // 26
this._stats.arrests = wrapper.readInt(); // 27

// flags & meta
this._stats.isAggressive = wrapper.readBoolean(); // 28
this._stats.working = wrapper.readBoolean(); // 29
this._stats.dead = wrapper.readBoolean(); // 30
this._stats.gangName = wrapper.readString(); // 31

return true;
}

public get stats(): UserStatsData {
return this._stats;
}

private _blank(): UserStatsData {
return {
userId: 0,
username: '',
figure: '',

health: 0,
maxHealth: 100,
energy: 0,
maxEnergy: 100,
hunger: 0,
maxHunger: 100,
aggressionMs: 0,

xp: 0,
maxXP: 100,
strength: 0,
level: 0,
points: 0,
stamina: 0,
hunger_level: 0,
gathering: 0,
defense: 0,

punches_thrown: 0,
punches_landed: 0,
damage_inflicted: 0,
damage_received: 0,
shifts_worked: 0,
kills: 0,
deaths: 0,
arrests: 0,

isAggressive: false,
working: false,
dead: false,
gangName: '',
};
}
}
